local Settings = {}

local function init()
    local config = FileUtil.getGameConfigFromCsv("GeneralProbability.csv")
    if not config then
        return
    end
    for _, item in pairs(config) do
        Settings[item.Type] = { TitleLang = item.TitleLang, HintLang = item.HintLang, List = {} }
    end
    config = FileUtil.getGameConfigFromCsv("GeneralProbabilityItem.csv")
    if not config then
        return
    end
    for _, item in pairs(config) do
        local setting = Settings[item.Type]
        if setting then
            table.insert(setting.List, {
                Index = tonumber(item.Index),
                Name = item.Name,
                ProbabilityLang = item.ProbabilityLang
            })
        end
    end
    for _, setting in pairs(Settings) do
        table.sort(setting.List, function(a, b)
            return a.Index < b.Index
        end)
    end
end

init()

GeneralProbability = {}

function GeneralProbability:getSettings(type)
    return Settings[type]
end